(window.webpackJsonp=window.webpackJsonp||[]).push([[111],{599:function(n,v,_){"use strict";_.r(v);var e=_(2),s=Object(e.a)({},(function(){var n=this,v=n._self._c;return v("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[v("p",[n._v("@"),v("a",{attrs:{href:"%E7%B3%BB%E7%BB%9F%E6%9E%B6%E6%9E%84%E8%AE%BE%E8%AE%A1%E8%AE%BA%E6%96%87%E7%9B%AE%E5%BD%95"}},[n._v("TOC")])]),n._v(" "),v("h2",{attrs:{id:"系统架构设计论文答题技巧"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#系统架构设计论文答题技巧"}},[n._v("#")]),n._v(" 系统架构设计论文答题技巧")]),n._v(" "),v("p",[n._v("考试时间 14:30 ~18:00"),v("br"),n._v("\n论文建议答题时间 16:00 ~ 18:00")]),n._v(" "),v("p",[n._v("字数一定要够 大概要写2500字左右。2024年开始 是机考了，也就是打字。")]),n._v(" "),v("p",[n._v("解答应分摘要和正文两部分\n要注意下面两点：\n① 摘要字数应控制在400字以内，可以分条叙述。\n② 正文字数为2000到3000 字，可以部分内容分条叙述，但不要全部内容都用分条叙述的方式。")]),n._v(" "),v("p",[n._v("系统架构设计师的论文考试给出四个题目，要求四选一。最好是选择自己最擅长的题目。")]),n._v(" "),v("p",[n._v("建议先 列出提纲5-10分钟，字数100-200字  主要是 为后面写大量文字理清思路。")]),n._v(" "),v("p",[n._v("下面都是论文的内容了：\n"),v("strong",[n._v("写摘要15-20分钟，300-400字")]),n._v("\n（摘要是对整个论文内容的精炼总结 非常重要）")]),n._v(" "),v("p",[v("strong",[n._v("写正文80分钟，2000字以上")]),n._v("\n(写正文的模板大致分为3个阶段\n①、系统(项目)介绍。这部分主要介绍系统背景、系统总体结构主要特点、自己担任的角色、主要工作等。这部分内容有400字左右，建议这部分内容在考前就准备好。因为稍微改改就能用在任何一篇上。\n②、论述部分。这部分内容是核心内容，涉及到对论点进行展开和论述，大概1300字左右。一般是采用结构化的方式分几点进行论述，可以首先简要介绍下考题提到的技术或问题，然后按照要求去展开论述。注意不要全部都按点论述。\n③、总结部分主要根据上述正文部分中，对系统（项目）实现过程中的开展情况进行汇总和分析，包括项目实施过程中成功的方面、可以改进的方面、失败的方面等。这部分300字。  主要写成功的方面和总结，不建议写失败的方面，可以稍微提一下不足点和可改进点即可。)")]),n._v(" "),v("h2",{attrs:{id:"论基于构件的软件设计和应用-完善"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#论基于构件的软件设计和应用-完善"}},[n._v("#")]),n._v(" 论基于构件的软件设计和应用 (完善)")]),n._v(" "),v("p",[v("strong",[n._v("题目：论基于构件的软件开发方法及其应用")]),n._v(" "),v("strong",[n._v('基于构作的软件开发 (Component-Based Software Development，CBSD) 是一种基于分布对象技术、强调通过可复用构件设计与构造软件系统的软件复用途径。基于构件的软件系统中的构件可以是COTS （Commercial-Off-the-Shelf）构件，也可以是通过其它途径获得的构件(如自行开发)。CBSD将软件开发的重点从程序编写转移到了基于已有构件的组装，以更快地构造系统，减轻用来支持和升级大型系统所需要的维护负担，从而降低软件开发的费用。\n请围绕“基于构件的软件开发方法及其应用"论题，依次从以下三个方面进行论述。')]),n._v(" "),v("strong",[n._v("1. 概要叙述你参与管理和开发的软件项目，以及你在其中所承担的主要工作。\n2. 详细论述基于构件的软件开发方法的主要过程。\n3. 结合你具体参与管理和开发的实际项目，请说明具体实施过程以及碰到的主要问题。")])]),n._v(" "),v("p",[n._v("范文：")]),n._v(" "),v("p",[n._v('       2022年7月，我所在公司成功承接xx电气有限公司的 "智融链商平台"系统的建设项目。我作为项目的系统架构师，主要完成了系统分析、架构设计工作。由于公司有智能化客户关系管理类行业软件的研发经验，并且有一定的技术积累和相应构件库，相关构件能够基于客户大数据和订单大数据，进行智能分析，生成精准客户画像以及订单偏好等商业智能（Business Intelligence，BI）报表。所以针对该系统采用了基于构件的软件开发方法。基于构件的软件开发方法包括以下活动：\n1.系统需求概览；2.识别候选构件；3.根据发现的构件修改需求；4.体系结构设计；5.构件的定制与适配；6.组装构件，创建系统。首先和各干系人详细沟通，明确用户需求，识别并标识可能使用的构件。然后进行架构设计，采用J2EE主流的轻量级架构，使用Spring、SpringMVC、MybatisPlus、SpringCloud框架作为系统的基础平台，在公司已有的架构基础上，复用已有的构件，开发所需新构件，实现系统的功能需求，保证项目按期、高质量的上线运行。 '),v("strong",[n._v("(摘要)")])]),n._v(" "),v("p",[n._v("       对于xx电气有限公司的销售员和各级部门领导来说，繁杂的物料规则、客户和分销商的各级经销关系、复杂的线下特价和退货等业务审批流程已经严重影响了该公司的工作效率和成单率，且该公司老版本的CRM系统无法支持线上审批和利用大数据分析客户和订单数据，xx电气有限公司的IT部门负责人希望能建设一个全新的智能CRM管理平台，支持管理复杂的客户分销商关系、线上复杂流程审批、物料个性化\n配置以及管理和追踪订单的整个业务流程，同时能够通过对客户和订单的大数据分析赋能营销部，提高客户转化率和成单率。“智融链商平台”就是为了满足以上需求而开发的，系统包括：智能BI分析转化模块、工作流模块、智能客户管理、物料配置管理、订单管理、售后管理、系统设置等七个模块。"),v("strong",[n._v("(项目背景)")])]),n._v(" "),v("p",[n._v("       构件是一个功能相对独立的，具有可重用价值的软件单元，封装了设计和实现的内容，并向外提供接口，通过接口与其它构件组装成功能更大的更复杂的整体。接口是用户与构件发生交互的连接渠道，第三方只能通过构件接口的规格说明理解和复用构件，按照接口要求进行通信。构件的获取可以有多种不同的途径：\n1.从现有的构件库中获得符合要求的构件，直接使用或作适当的修改满足要求，得到可重用的构件；\n2.通过遗留工程，将具有潜在重用价值的构件从原有的系统中提取出来，得到可重用的构件；\n3.从市场上购买符合我们要求的现成的商业构件，即COTS构件；\n4.开发新的符合要求的构件。\n基于构件的软件开发方法强调通过复用已有的构件将开发的重点从程序编写转移到已有构件的组装，以便更快地构造系统，提高开发效率和系统质量，降低软件开发成本。基于构件的软件开发方法主要包括以下活动：\n1.系统需求概览；\n2.识别候选构件；\n3.根据发现的构件修改需求；\n4.体系结构设计；\n5.构件的定制与适配；\n6.组装构件，创建系统。\n由于我们公司有CRM类行业软件的研发和智能数据分析经验，有大量的技术积累和构件库，并且有多个CRM行业类智能管理项目正在开展，所以我们针对该系统采用了基于构件的软件开发方法。在已有的领域模型基础之上，重用基础设施，例如重用我公司的工作流引擎组件完成线上流程审批业务，完成系统的架构设计，通过大量使用可复用构件，采用基于构件的建造方法实现快速开发出高质量的系统。下面基于本系统开发过程展开介绍。 （技术介绍）")]),n._v(" "),v("p",[n._v("一、系统需求概览\n       在需求获取的过程中，我们主要采用了面谈、到客户现场观摩和调查问卷等方式，对于xx电气公司的工作人员，因为平时和他们讨论需求的接触的比较多，而且他们对业务流程也非常清楚，所以我们采用面谈的方法来获取需求，在面谈的过程中，我们着重引导客户把实际工作中最重要的部分进行更加详细的讨论。对于xx电气公司的客户和分销商，由于数量庞大、且分布在全国各地还有部分客户在东南亚地区，所以我们采用了线上问卷调查来获取需求，通过合理设置调查问卷、发给被调查企业，在直接领导的督促下，企业填完后我们进行收集整理，针对重点问题、有价值的问题和建议，再通过走访、现场观摩的方式，详细沟通了解细节，获取大量一手资料，为我们后续的架构设计奠定基础。")]),n._v(" "),v("p",[n._v("二、识别候选构件\n       根据前期获取的需求，按照关键字法来检索构件库，查找可能需要的构件，根据找到构件的功能描述或行为说明文档来初步判断是否能满足本系统要求。如果可以满足要求，则进行标识，列为候选构件。")]),n._v(" "),v("p",[n._v("三、根据发现的构件修改需求\n       比如根据我们初步选择的“全局异步导出”构件，用户只需要点击导出按钮，系统就可以自动为用户保留此次导出文件，且在导出过程中，不影响用户的其他操作。如果使用该构件，对于整个平台的报表导出功能都可复用该构件，能够大量节约后期开发时间。在后续与用户的沟通过程中，我们向用户解释我们提供的导步构件的性能优势和用户友好性，说服用户接受了此功能需求。我们的构件可以不用修改就能使用。能够大量节约后续所有的导出报表功能的开发时间。")]),n._v(" "),v("p",[n._v("四、体系结构设计\n       根据前期获取的需求，对系统进行结构化分析，得到系统的数据流图(DFD)和功能结构图(SC)。在此基础上，首先提取系统所需的各种功能模块，然后确定系统的总体框架，绘制出整体框架的功能图---包括每个具体的功能模块，和各功能的外部关系和实现条件。采用J2EE主流的轻量级架构，使用Spring、SpringMVC、Mybatis框架作为系统的基础平台，系统分为表现层、业务逻辑层和数据访问层，还包括一个三方平台系统集成层。在表现层，企业通过TCP/IP方式和应用层交互信息，以页面和数据报表等多种方式将数据展示出来，供用户使用。三方平台集成层，涉及数据较多，除从本系统获取数据外，还需要从其它系统平台，如：xx电气公司的OA系统，和WMS系统获取一些审批和报表数据，以支持本系统的审批需要。业务逻辑层是系统的核心，负责处理系统中的各类业务逻辑，采用Spring框架技术实现。架构设计完成后，我们结合客户要求，邀请了领域专家，采用组织讨论会议的形式，对架构设计进行了评审，看该架构是否可以满足系统功能要求和质量要求。通过专家讨论，一致认为架构设计能够达到系统要求。")]),n._v(" "),v("p",[n._v("五、构件的定制与适配\n       在系统构建过程中，有针对性的选择构件，可以大大提高系统的开发效率，节省时间，降低成本，保证质量。由于我们公司一直从事的就是CRM类行业智能软件的开发，有着完善的构件库，所以在构建过程中，对于我们已有的构件(前期列为候选构件)，直接使用，对于没有的才进行重新开发。比如，对于客户分销商物料等模块的分页数据查询和报表的异步导出，还有线上流程审批追踪，客户数据订单数据的智能BI分析，我们有专门的实现了相关功能的构件。当现有的构件不能满足需要的时候，我们就全新开发，如分布式事务的控制，是需要新开发的一个构件，它负责在各个服务调用数据库时，确保数据的一致性和完整性。对于全新开发的构件，我们按照公司的标准和要求，严格定义、开发、测试并形成相关文档，最后存入公司的构件库，以便将来的项目复用。对于一些修改使用的构件，如数据格式转换构件，我们也对它进行详细描述，指定版本号和各版本之间的差异，以便将来针对不同的情况，使用不同版本的构件。我认为对于软件构建不仅仅是功能开发完成就结束了，对构件的描述和分类存放也同样至关重要，只有有完善文档和分类存放的构建在后续项目\n复用构件时才能更加快速的查找使用。")]),n._v(" "),v("p",[n._v("六、组装构件，创建系统\n       构件之间的组装关系由组装逻辑描述，组装逻辑规定了各个构件之间的作用形式和构件在运行期间的通信机制。根据我们复用的构件和全新开发的构件，按接口要求和整体框架功能图进行了组装，实现了系统功能。在系统的实现过程中，用户提出了一些需求变更，对于这些变更，我们在演化过程中进行了增加、实现。各功能模块实现后，还进行了测试，由于实现过程中使用了大量可复用的构件，这些复用构件质量经过了实践的检验，按照要求进行了总体测试，对新创建的构件，我们按测试计划要求，严格进行了测试。\n(正文)")]),n._v(" "),v("p",[n._v("三、总结\n       2023年3月，整个项目顺利完成，通过近一年的用户使用反馈，整个系统运行稳定，达到了预期的目标和要求，受到了用户的好评。但也存在些不足，比如在一些大数据量同步的时候，出现过JVM内存不足的情况，导致部分数据同步失败，后来我们及时优化了相关应用的JVM内存参数，解决了这个问题。 （总结142字、正文3437字）")]),n._v(" "),v("h2",{attrs:{id:"论系统安全架构设计及其应用-完善"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#论系统安全架构设计及其应用-完善"}},[n._v("#")]),n._v(" 论系统安全架构设计及其应用(完善)")]),n._v(" "),v("p",[v("strong",[n._v("题目：论系统安全架构设计及其应用")]),n._v("\n信息安全的特征是为了保证信息的机密性、完整性、可用性、可控性和不可抵赖性。信息系统的安全保障是以风险和策略为基础，在信息系统的整个生命周期中提供包括技术、管理、人员和工程过程的整体安全，在信息系统中保障信息的这些安全特征，并实现组织机构的使命。许多信息系统的用户需要提供一种方法和内容对信息系统的技术框架、工程过程能力和管理能力提出安全性要求，并进行可比性的评估、设计和实施。请围绕“论系统安全架构设计及其应用”论题，依次从以下三个方面进行论述。\n"),v("strong",[n._v("1、概要叙述你所参与管理或开发的软件项目，以及你在其中所承担的主要工作。\n2、详细论述安全架构设计中鉴别框架和访问控制框架设计的内容，并论述鉴别和访问控制所面临的主要威胁，并说明其危害。\n3、阐述你在软件开发的过程中都遇到了哪些实际问题及解决方法。")])]),n._v(" "),v("p",[v("strong",[n._v("范文：")])]),n._v(" "),v("p",[n._v('一、摘要\n       2022年6月，我所在公司成功承接xx电气有限公司的 "智融链商平台"（包括智能报表、线上流程审批、物料管理、权限管理等模块）建设项目。系统采用微服务的架构设计，系统按业务独立性和处理共性，划分为权限服务、流程服务、物料服务、客户服务、BI服务、订单服务等6个服务中心，各服务通过互联网协议进行通信，通过微服务架构设计给平台带来了很好的拓展性和可维护性。但在系统安全性方面，尤其是用户鉴权和访问控制在微服务架构的系统中会变得更加复杂。本文以此项目为基础，首先介绍了鉴权框架和访问控制框架的内容及其面临的问题，然后详细介绍了项目中采用的微服务架构权限管理模型解决鉴权和权限管理，以及单点登录问题、集中访问控制问题。我作为项目的架构师，主要完成了需求分析、系统架构设计等工作。')]),n._v(" "),v("p",[n._v("二、正文\n（第一段 项目背景）\n      xx电气有限公司的销售员和各级部门领导察觉到该公司业务规则中繁杂的物料规则、客户和分销商的复杂经销关系、复杂的线下特价和退货等业务审批流程已经严重影响了该公司的工作效率和成单率，并且该公司旧版本的CRM系统无法支持现有复杂业务的线上审批和利用大数据相关技术分析客户和订单数据，xx电气有限公司的IT部门负责人希望能建设一个全新的智能CRM管理平台，支持管理复杂的客户分销商关系、线上复杂流程审批、物料个性化配置以及管理和追踪订单的整个业务流程，同时能够通过对客户和订单的大数据分析赋能营销部，提高客户转化率和成单率。“智融链商平台”就是为了满足以上需求而开发的，系统包括：智能BI分析转化模块、工作流模块、客户智能化管理、物料配置管理、订单管理、售后管理、系统设置等七个模块。系统采用微服务架构设计，微服务具备很高的灵活性和可伸缩性且各个服务支持独立开发和部署，使得开发人员能够更加灵活的应对客户多变的需求。但在系统安全性方面，尤其是鉴权和访问控制在微服务架构的信息系统中会变得更加复杂。通过认真研究ISO开放系统互联安全体系的5类安全服务：鉴别、访问控制、数据机密性、数据完整性、抗抵赖性，我们将鉴别框架和访问控制框架设计作为系统安全的重要内容，下面结合该项目从鉴别框架和访问控制框架设计方面分别进行详细说明。")]),n._v(" "),v("p",[n._v('一、鉴别框架\n     鉴别是一种用来对实体和其所呈现身份之间的绑定关系进行充分确认的过程，该过程为实体所声明的身份提供保障。简单来说就是确认访问者是否是他宣称的身份。\n我们可以通过下面鉴别因素对实体进行鉴别：\n我们可以通过下面的身份鉴别因素对实体进行鉴别：\n所知因素：这包括某个人知道的信息，比如密码、个人识别码等。\n所有因素：这包括某个人所拥有的鉴别物品，如设备签名、IC卡、U盾等。\n生物因素：这包括某个人的生物特性，比如指纹、虹膜等生物特征。\n行为因素：这包括某个人的行为，可以通过个人的习惯、行为模式等来识别身份。\n环境因素：这包括与特定环境相关的因素，比如主机IP地址等。\n这些因素被广泛运用在身份鉴别与认证系统中，以确保对实体的准确鉴别和验证。鉴别阶段的威胁包括与鉴别过程中凭证使用有关的威胁以及鉴别的一般性威胁。\n鉴别的一般性威胁包括：恶意软件(如病毒、木马、击键记录软件)、社交工程(如偷窥、盗窃硬件和个人识别码)、在数据传输过程中非法截获或修改鉴别数据、拒绝服务以及程序性缺陷等。针对xx电气有限公司的 "智融链商平台"，根据信息安全性要求和功能的具体实现，我们设计了不同的鉴别方式。比如针对智融链商平台PC终端用户，使用了用户密码和主机地址的验证方式。因为整体网络架构都是预先设计好的，只有在固定的网段内的主机才可以以管理员的身份通过密码进行登录。如果用户使用的是手机或平板等智能移动终端，还可以使用人脸识别方式和手机验证码方式进行验证登录。')]),n._v(" "),v("p",[n._v("二、访问控制框架\n     访问控制指防止对任何资源进行未授权的访问，从而使计算机系统在合法的范围内使用。指用户身份及其所归属的某项定义组来限制用户对某些信息项的访问，或限制对某些控制功能或服务的使用的一种技术。常见的访问控制模型包括：\n1.自主访问控制模型(DAC)，是根据自主访问控制策略建立的一种模型，允许合法用户以用户或用户组的身份访问策略规定的客体，同时阻止非授权用户访问客体。\n2.权限控制列表(ACL)，每一个客体都配有一个列表，这个列表记录了主体对客体进行何种操作。当系统试图访问客体时，先检查这个列表中是否有关于当前用户的访问权限。\n3.强制访问控制模型(MAC)，是为了弥补DAC权限控制过于分散的问题而诞生的。它非常适合机密机构或者其他等级观念强烈的行业如军事部门，但过重强调保密性，管理不够灵活。\n4.基于角色的访问控制(RBAC)是目前信息系统中广泛认可的访问控制模型，该模型强调三个要素：用户、角色、权限。在用户和权限之间引入了“角色”的概念，角色解耦了用户和权限之间的关系。它把权限赋予角色，再把角色赋予用户。用户和角色，角色和权限都是多对多的关系。用户拥有的权限等于所拥有角色的权限之和。上述模型可以很好的解决权限的管理，但在网络传输时，还是常常遇到诸如重放攻击、会话劫持、中间人攻击等网络威胁，通过伪造身份严重威胁信息安全。\n而且在微服务的架构下，传统的RBAC权限管理模型不能满足服务场景的需求，体现在服务间调用权限和权限控制粒度问题等信息的管理。\n     此外，还有：1.单点登录(SSO)问题。在微服务场景下，访问请求往往是无状态的，这就意味着每次请求都需要进行权限校验，但是系统需要单个身份认证的访问入口，以减少频繁的身份认证环节。单点登录使得每个提供资源的服务都必须与认证服务交互，这会产生大量的网络开销。2.集中访问控制问题。每个服务拥有独立的访问控制模块，针对浏览器或者其他服务发来的请求，在服务内部进行权限校验,来判断该请求是否有访问权限。\n如何设计一个统一权限数据库，从而减轻维护成本。基于上述问题，我们设计出了微服务架构的权限管理模型。该模型可以提供一套微服务架构下包含服务间权限管理、服务实例信息管理等细粒度权限管理机制。")]),n._v(" "),v("p",[n._v("     具体的微服务架构下权限管理模型完成鉴权及访问控制过程主要分为用户身份认证、用户权限查询匹配、校验权限是否合法三个过程。下面详细介绍项目中的权限校验过程。\n首先用户在登录页面通过输入用户名与密码组合，如果提交的用户密码信息经过加密后与后台数据库存储的Bcrypt加盐加密过的密码信息吻合，则视为身份认证通过。接下来授权服务通过计算该用户角色的权限与用户权限的并集获取该用户的全部权限信息。Auth服务根据用户与权限信息生成该用户Token信息，通过发放Token信息给客户端从而实现访问控制。最后，浏览器将Token信息存至本地Cookie中，在下次请求中将Cookie中的Token信息放至HTTP请求的头部。\n在鉴权服务获取到Token信息后，获取出此用户的权限信息，并将请求的功能权限与数据信息进行比对，信息一致的请求路由至指定的服务，不一致则向客户端回复没有访问权限。这种管理方式的优势在于：一方面访问控制更加集中，有统一对外的权限校验入口，可以将非法请求隔离在系统的外部。另一方面方便访问控制，可以统一进行权限管理以及维护，提高管理效率，并且增加了服务间权限管理处理，可以满足对权限管理要求的灵活性与拓展性。")]),n._v(" "),v("p",[n._v("三、总结\n     2023年3月，整个项目顺利完成，通过近一年的用户使用，整个系统运行稳定，安全性良好，达到了预期的目标和要求，受到了用户的好评。但也存在些不足，比如由于权限统一管理，当不同服务的权限信息需要随着业务改变时，需要对统一的权限服务进行修改，会出现权限管理数据库的信息变更或者需要重启鉴权服务，这是以后在项目中需要加以改进的地方。但总的来说，项目是成功的，我也通过这个项目学习到了不少经验。今后我将继续加强学习，总结经验教训，提高自己的能力。")]),n._v(" "),v("h2",{attrs:{id:"论数据分片技术及其应用"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#论数据分片技术及其应用"}},[n._v("#")]),n._v(" 论数据分片技术及其应用")]),n._v(" "),v("p",[v("strong",[n._v("题目：论数据分片技术及其应用")]),n._v("\n数据分片就是按照一定的规则，将数据集划分成相互独立正交的数据子集。然后将数据子集分布到不同的节点上，通过设计合理的数据分片规则，可将系统中的数据分布在不同的物理数据库中达到提升应用系统数据处理速度的目的。请围绕“论数据分片技术及其应用”论题，依次从以下三个方面进行论述。\n"),v("strong",[n._v("1、概要叙述你参与管理和开发软件的项目以及承担的工作。\n2、Hash分片、一致性Hash分片和按照数据范围分片是三种常用的数据分片方式。\n3、具体阐述你参与管理和开发的项目采用了哪些分片方式，并且具体说明其实现过程和应用效果。")])]),n._v(" "),v("p",[v("strong",[n._v("范文：")])]),n._v(" "),v("p",[n._v("一、摘要\n2019年2月，我所在的公司成功中标**省生态环境厅的信息化综合服务平台(包括污染源在线监控系统，空气质量指数(AQI)实时自动发布系统，重点排污单位监控系统，危险废物处置系统，网上审批系统等)建设项目，该平台主要解决污染企业、产废企业、处置企业业务申报和环境执法部门对相关企业的在线监督、业务审批和管理。我作为项目的架构师和技术负责人，主要完成了需求获取分析、系统架构分析和设计等工作。本文以此项目为基础首先介绍了常用到的数据库分片技术，然后介绍了我们这个项目采用数据分片技术(一致性Hash分片和按数据范围分片相结合)以及ceph技术架构及实施。经过全体团队成员一年的努力，平台开发完成并顺利上线，通过近一年的用户反馈，整个系统运行稳定，达到了预期的目标和要求。\n(摘要320字)")]),n._v(" "),v("p",[n._v("二、正文\n(项目背景)\n目前，环境保护是每一个省市地方政府和人民群众都十分关心的问题，国家也对各级地方政府在环保方面提出了更高的要求，为了满足人民群众需求、方便企业办事，省生态环境厅决定开发生态环境厅信息化综合服务平台，平台包括多个系统，如空气质量指数(AQI)实时自动发布系统，我们通过手机APP等终端就可以实时了解空气质量;网上审批系统帮助企业方便快捷的办理各项业务申报;重点排污单位监控系统帮助环境监督和执法部门对各排污企业进行实时监督和管理，防止企业偷排偷倒。由于平台涉及自动发布和实时监控系统，每分每秒都会产生大量数据进行存储而且平台涉及全省11个地级市上万家重点排污企业的实时监控所以系统的可靠性、稳定性、及时响应成为需要高度关注的问题，经过讨论研究，底层的数据存储我们决定采用数据分片技术，将系统中的数据分布存储在不同的节点，提高系统运行的可靠性，提升系统数据处理速度，增强系统的可扩展性。下面结合该项目对数据分片技术进行介绍。\n(404字)")]),n._v(" "),v("p",[n._v("数据分片就是按照一定的规则，将数据集划分成相互独立正交的数据子集。然后将数据子集分布到不同的节点上。常见的数据分片算法包括Hash 分片、一致性Hash分片和按照范围数据分片三种，\n1.Hash 分片。哈希表(散列表)是最为常见的数据结构，根据记录(或者对象)的关键值将记录映射到表中的一个(slot)便于快速访问。最为简单的散列函数是 mod N(N为表的大小)即将hash值对N取余，余数即在表中的位置。hash分片的道理是一样的，首先按照数据的某一特征(key)来计算哈希值，并将哈希值与系统中的节点建立映射关系，从而将哈希值不同的数据分布到不同的节点上。比如系统中存在3个存储结点(Node0、Node1、Node2)，对Hash 值模3，得出的结果就是要存入缓存节点的序号。hash分片映射关系简单，需要管理的元数据也非常少，只需要记录节点的数目以及hash方式就行了。但hash方式的缺点也非常明显:当增加或者减少存储节点时，之前建立的映射关系会失效。\n2.一致性Hash分片。用一致性 Hash 算法可以很好地解决增加和删减节点时，映射关系失效的问题。一致性 Hash 算法将整个 Hash值空间组织成一个虚拟的圆环，然后将存储节点的IP地址或者主机名做 Hash 取值后，放置在这个圆环上。当我们需要确定某一个 Key 需要存取到哪个节点上的时候，先对这个 Key 做同样的Hash 取值，确定在环上的位置，然后按照顺时针方向在环上“行走”，遇到的第一个缓存节点就是要访问的节点。一致性 Hash算法解决了增加删除节点时大量映射关系的问题，但是，一致性hash方式在增加节点的时候，只能分摊一个已存在节点的压力; 同样，当某个节点故障时，该节点承担的所有访问都会被顺移到另一个节点上，会对后面这个节点造成很大压力。我们希望在增删节点的时候，已存在的所有节点都能参与响应，达到新的均衡状态。因此，在实际工程中，引入虚拟节点的概念。即不是将物理节点映射在hash环上，而是将虚拟节点映射到hash环上。虚拟节点的数目远大于物理节点，因此一个物理节点需要负责多个虚拟节点的真实存储。操作数据的时候，先通过hash环找到对应的虚拟节点，再通过虚拟节点与物理节点的映射关系找到对应的物理节点。")]),n._v(" "),v("p",[n._v("3.按照范围数据分片。就是按照时间区间或ID区间来切分。比如按年份将数据分散存储到不同的库(表)中;因为有些系统使用的数据可能存在着冷热不均的特点，比如最近一年的数据使用频率高，之前年份的数据使用率低，将使用较少的历史数据迁移到其他库中，提高查询的效率。我们结合数据分析技术特点和用户需求，采用了一致性Hash分片和按照范围数据分片相结合的方式。由于污染源在线监控系统空气质量指数(AQI)实时自动发布系统产生的数据量大，时间性强我们采用按季度进行数据分片，每个季度的数据存储在一个表中。对于重点排污单位监控系统等采用一致性Hash分片技术，采用Ceph集群部署了6个0SD节点和3个MON节点，每个OSD节点配备2块1TB SSD磁盘，12块8TBSATA磁盘，SSD磁盘和SATA分别用于Journal日志和数据存储，因为Ceph使用日志来提高性能及保证数据一致性。使用SSD作为OSD的日志盘来提高集群性能，OSD存储服务主要功能是存储数据、平衡数据、恢复数据以及与其它osD间进行心跳检查等。每一个osD进程都可称作是一个oSD节点每个0SD节点监听不同的端口，每个0SD节点可以设置一个目录作为实际存储区域，一般对应一整块硬盘。MON监控服务主要负责监控整个集群，每个ceph集群中至少要有一个MON节点，维护集群的健康状态，维护展示集群状态的各种图表，如OSD Map\nMonitor Map、PG Map和CRUSH Map。采用一主两从的架构，总计提供的存储容量大约为290TB。每个0SD节点使用4条万兆网络每2条绑定，分别连接外部公共网络和内部网络。Ceph采用CRUSH算法，数据存储到ceph集群时，首先将数据先被分割成多个4MB的 object(大小可以设置)，每个对象对应有Object id。因为object的size很小，在一个大规模的集群中可能有几千万个对象，这样导致遍历寻址速度会非常缓慢的，并且如果将对象直接通过某种固定映射的哈希算法映射到oSD上，当某个OSD损坏时，对象无法自动迁移至其他0sD上面。为了解决这些问题，ceph引入了归置组的概念，即PG。PG类似于数据库中的索引，每个对象都会固定映射进一个PG中，所以当我们要寻找-个对象时，只需要先找到对象所属的PG，然后遍历这个PG就可以了，无需遍历所有对象，提高了遍历的速度。而且在数据迁移时也是以PG作为基本单位进行迁移，Ceph不会直接操作对象。PG再通过CRUSH计算，映射到OSD中。如果是三副本的，则每个PG都会映射到三个OSD，保证了数据的冗余。(正文2200字)")]),n._v(" "),v("p",[n._v("三、总结\n2020年1月，整个项目顺利完成，通过近一年的用户使用，整个系统运行稳定，达到了预期的目标和要求，受到了用户的好评。但也存在些不足，比如在数据同步的时候，偶尔出现部分数据同步失败的提示，后来我们及时更新数据同步程序，解决了这个问题。这是以后在项目中需要注意的地方。但总的来说，项目是成功的，我也通过这个项目学习到了不少经验。今后我将继续加强学习，总结经验教训，提高自己的能力。\n(总结180字 全文2700字)")]),n._v(" "),v("h2",{attrs:{id:"论面向服务架构设计及其应用"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#论面向服务架构设计及其应用"}},[n._v("#")]),n._v(" 论面向服务架构设计及其应用")]),n._v(" "),v("p",[v("strong",[n._v("题目：论面向服务架构设计及其应用")]),n._v("\n面向服务架构(Service-Oriented Architecture, SOA) 是一种应用框架，将日常的业务应用划分为单独的业务功能服务和流程，通过采用良好定义的接口和标准协议将这些服务关联起来。通过实施SOA的系统架构，用户可以构建、部署和整合服务，无需依赖应用程序及其运行平台，从而提高业务流程的灵活性，帮助企业加快发展速度，降低企业开发成本，改善企业业务流程的组织和资产重用。\n请围绕“论面向服务架构设计及其应用”论题，依次从以下三个方面进行论述。\n"),v("strong",[n._v("1.概要叙述你参与分析和开发的软件系统开发项目以及你所担任的主要工作。\n2.说明面向服务架构的主要技术和标准，详细阐述每种技术和标准的具体内容。\n3.详细说明你所参与的软件系统开发项目中，构建SOA架构时遇到了哪些问题，具体实施效果如何。")])]),n._v(" "),v("p",[v("strong",[n._v("范文：")])]),n._v(" "),v("p",[n._v('      2022年6月，我所在公司成功中标xx电气有限公司的 "智融链商平台"系统的建设项目。我作为项目的系统架构师和技术负责人，主要完成了需求的获取、分析，系统的架构设计等工作。该项目是基于互联网，为xx电气有限公司的工作人员和该公司的全体分销商相关业务人员提供下单、流程审批、物料管理、权限管理、基于客户大数据和订单大数据，进行智能分析，生成精准客户画像以及订单偏好等商业智能（Business Intelligence，BI）报表的服务平台。本文以此项目为基础，介绍了面向服务架构在项目开发过程的应用。首先简要描述了面向服务架构的主要技术和标准，然后具体阐述该平台面向服务架构设计层次:底层传输层、服务通信协议层、服务描述层、业务流程层和服务注册层。最后说明采用面向服务架构设计在开发过程中遇到的实际问题和解决方法。经过9个月的努力，平台开发完成并顺利上线，通过近一年的用户反馈，整个系统运行稳定，达到了预期的目标和要求。')]),n._v(" "),v("p",[n._v("二、正文\n      对于xx电气有限公司的销售员和各级部门领导来说，繁杂的物料规则、客户和分销商的各级经销关系、复杂的线下特价和退货等业务审批流程已经严重影响了该公司的工作效率和成单率，且该公司老版本的CRM系统无法支持某些复杂流程的线上审批和利用大数据分析客户和订单数据进行智能分析的功能。xx电气有限公司的IT部门负责人希望能建设一个全新的智能CRM管理平台，支持管理复杂的客户分销商关系、线上复杂流程审批、物料个性化配置以及管理和追踪订单的整个业务流程，同时能够通过对客户和订单的大数据分析赋能营销部，提高客户转化率和成单率。“智融链商平台”就是为了满足以上需求而开发的，系统包括：智能BI分析转化模块、工作流模块、客户智能化管理、物料配置管理、订单管理、售后管理、系统设置等七个模块。")]),n._v(" "),v("p",[n._v('      面向服务架构设计(SOA)是一种软件架构，同时也是一种软件设计方法和理念，它将应用程序的不同功能单元(称为服务)通过这些服务之间定义良好的接口和契约联系起来。接口是采用中立的方式进行定义的，它独立于实现服务的硬件平台、操作系统和编程语言。这使得构建在各种系统中的服务可以以一种统一的方式和"智融链商平台"系统进行交互。比如，需要读取“WMS库存管理系统”的库存信息，系统的订单交期管理模块，需要读取“APS排产系统”中的交期信息等。SOA具备的“接口标准可访问”和“易于扩展”等特点，使得开发人员能方便的集成企业的多种业务系统，并且以最小的软件变更应对多变的客户需求。所以，经过详细调研、分析讨论，最终我们决定系统采用面向服务架构设计(SOA)来实现。')]),n._v(" "),v("p",[n._v("      面向服务架构的主要技术标准有WSDL(Web服务描述语言)、UDDI(统一描述、发现和集成)、SOAP(简单对象访问协议)。WSDL用来描述服务，描述如何访问具体的接口，通过WSDL描述的服务信息。使不了解这个服务的开发者可以建立调用这个服务的客户端代码，或者通过WSDL帮助生成实现它的基本代码结构;UDDI用来注册和查找服务;而SOAP，是一种简单的、轻量级的基于XML的机制，用于在网络应用程序之间进行结构化数据交换，用来在服务消费者和服务提供者之间传送消息。一个服务消费者可以在UDDI注册表查找服务，取得服务WSDL描述，然后通过SOAP来调用服务。\n一、系统架构设计\n在进行架构设计时，我们将系统划分为5个层次:底层传输层、服务通信协议层、服务描述层、业务流程层和服务注册层。\n(1)底层传输层。底层传输层主要负责消息的传输机制，采用HTTP协议作为Web服务的消息传输协议。\n(2)服务通信协议层。服务通信协议层采用Dubbo协议，结合OpenAPI规范来描述并定义服务之间进行消息传递所需的技术标准。我们采用Dubbo的RPC(远程过程调用协议)作为一致性的调用协议，使用Hessian序列化后的Java对象字节流作为数据传送的格式，从而实现服务提供者和服务消费者的通信。\n(3)服务描述层。服务描述层采用WSDL来描述服务的接口与消息交换方式。方便开发者建立和实现调用这个服务的客户端代码\n(4)业务流程层。业务流程层是系统的核心，负责处理系统中的各类业务逻辑，涉及数据较多，除从本系统获取数据外，还需要从其它系统，如:在APS交期预测系统、WMS库存管理系统等获取数据，以支持本系统的审批需要。业务流程层用于支持服务发现服务调用和点到点的服务调用，并将业务流程从Web服务的底层调用抽象出来。\n(5)服务注册层。服务提供者通过 Dubbo 框架将自己的服务发布到注册中心ZooKeeper上，注册中心负责记录服务提供者的地址。服务消费者通过 Dubbo 框架从注册中心订阅服务提供者的地址，以便能够调用服务。ZooKeeper支持web服务的创建、描述、发现和调用，使得基于互联网的智融链商平台各服务之间能够共享信息、应用服务发现与交互，为各系统提供标准接口和数据结构。")]),n._v(" "),v("p",[n._v("二、应用开发实现在系统开发阶段，一是基于公司原有的构件库，按照WSDL接口标准来封装成web服务，快速构建服务网关、服务负载均衡、服务容错、分布式缓存等，为系统开发提供了运行基础。二是抽取分布式调度服务作为基础服务，采用任务“统一调度管理、分布式执行”模式，提供各应用任务的统一管理和应用间任务协作服务，并可为其他项目建设重用。")]),n._v(" "),v("p",[n._v("三是基于IDEA、Maven等工具，定制需要全新开发的服务，包括订单服务、物料服务、智能BI报表服务等，按照接口标准进行实现和描述。下面以“智能BI报表”服务来介绍基于Dubbo框架的服务实现。\nDuble-RPC是“一种远程过程调用（RPC）的技术”，其目的就是要实现远程分布式的透明调用。客户端在本地可以“直接”调用远程的服务接口，并得到返回结果。其核心就是Dubbo 使用序列化技术将 Java 对象转换为字节流进行网络传输，然后在接收端将字节流反序列化为 Java 对象。Dubbo 默认使用 Hessian 作为序列化协议，也可以通过配置切换至其他序列化协议，如 JSON 或者 Protobuf。但是考虑到Java对象\n序列化的性能和安全性我们采用的是Hessian作为序列化协议。\n在Dubbo中，服务提供者将自己的服务注册到ZooKeeper中，包括服务的地址、接口、版本等信息。同时，服务消费者通过Dubbo客户端去ZooKeeper中订阅所需服务，Dubbo客户端会监听ZooKeeper上服务提供者的变化情况。当服务提供者上线或者下线时，ZooKeeper会通知Dubbo客户端，客户端收到通知后会更新本地的服务列表。当服务消费者需要调用某个服务时，Dubbo客户端会根据服务的负载均衡策略选择合适的服务提供者，并通过网络请求调用相应的服务。\n客户端发起调用需要做的事就是通过Duble创建基于Hessian序列化的RPC请求消息，然后通过ZooKeeper注册中心订阅服务提供者的地址，找到对应服务，调用相应的接口获取接口返回的数据。\tDubbo接收到服务提供者的数据后，通过Hessian完成字节流反序列化成Java对象的操作。在做系统架构设计的时候，由于涉及众多分销商客户的大量订单数据的BI报表分析问题通过需求调研，我们发现，不仅仅是BI服务的功能实现，而且涉及到大量并发请求分析可能导致的性能问题，这就要求我们在着手设计结构框架时，必须要全面的考虑系统性能问题，同时客户还要求系统能够提供高可用服务。而这可能会极大的增加我们的工作量，比如，如何完成同一个服务的集群部署问题和负载均衡问题等。在这种情况下整个系统对于服务的性能和可用性需求就会比较复杂。\n我们通过细心的调研，把需要响应并发请求较高服务进行精确定位，形成统一完备的集群服务体系，同时结合客户提供的服务器规格自定义了加权轮询的负载均衡算法，使得性能高的服务器被调用的次数按照权重分配高于性能次之的服务器。保证服务器性能的充分利用，并且能够动态地调整调用策略，从而实现了系统中服务的高可用性和可伸缩性。")]),n._v(" "),v("p",[n._v("      2023年3月，整个项目顺利完成，通过近一年的用户反馈，整个系统运行稳定，达到了预期的目标和要求，受到了用户的好评。在项目的开发过程中，我们也遇到了一些问题，比如在xx电气有限公司进行物料库存数据同步的时候，由于服务是集群部署导致同步接口被多次调用的情况，后来我们通过Redis实现分布式锁解决了这个问题。该系统也为后期我们采用面向服务架构开发奠定了基础。")]),n._v(" "),v("h2",{attrs:{id:"论分布式存储系统架构设计-完善"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#论分布式存储系统架构设计-完善"}},[n._v("#")]),n._v(" 论分布式存储系统架构设计(完善)")]),n._v(" "),v("p",[v("strong",[n._v("题目： 论分布式存储系统架构设计")]),n._v("\n分布式存储系统（Distributed Storage System）通常将数据分散存储在多台独立的设备上。传统的网络存储系统采用集中的存储服务器存放所有数据，存储服务器成为系统性能的瓶颈，也是可靠性和安全性的焦点，不能满足大规模存储应用的需要。分布式存储系统采用可扩展的系统结构，利用多台存储服务器分担存储负荷，利用位置服务器定位存储信息，它不但提高了系统的可靠性、可用性和存取效率，还易于扩展。请围绕“分布式存储系统架构设计”论题，依次从以下三个方面进行论述。\n"),v("strong",[n._v("1、概要叙述你参与分析和开发的分布式存储系统项目以及你所承担的主要工作。\n2、简要说明在分布式存储系统架构设计中所使用的分布式存储技术及其实现机制，详细叙述你在具体项目中选用了哪种分布式存储技术，说明其原因和实施效果。\n3、冗余是提高分布式存储系统可靠性的主要方法，通常在分布式存储系统设计中可采用哪些冗余技术来提升系统的可靠性？你在具体项目中选用了哪种冗余技术？说明其原因和实施效果。")])]),n._v(" "),v("p",[v("strong",[n._v("范文：")])]),n._v(" "),v("p",[v("strong",[n._v("摘要")]),n._v("\n     2022年3月，我所在的技术团队成功中标XX电气有限公司的“全链路订单分析与库存管理系统”（包括智能报表、库存动态、物流跟踪等模块）建设项目，该系统以互联网为基础，采用微服务的架构设计，按业务独立性和处理共性，划分为BI报表服务、库存服务、订单服务、物料服务、物流服务、系统服务等6个服务中心。系统面向该公司全国乃至全球客户的订单交易活动，实时处理大量的订单信息、库存动态、物流跟踪等重要数据，对数据的存储和处理能力提出了极高的要求。鉴于该系统需要应对数据规模庞大，且分布广泛等特点，我们决定采用MySQL数据库与Mycat2分布式中间件相结合的方案，设计并实施了一套高效稳定的分布式数据库系统。我作为项目架构师,主导了项目的需求分析、系统架构设计和关键技术攻关等工作。本文以此项目为基础，首先介绍了数据库存储在应对大数据量和分布式存储数据所面临的问题，然后详细介绍了项目中采用的MySQL和Mycat2结合实现的分布式存储架构方案。")]),n._v(" "),v("p",[v("strong",[n._v("正文")])]),n._v(" "),v("p",[n._v("     随着国内工厂自动化进程不断加快和电动汽车行业的迅猛发展，电气类相关商品交易数据呈现出爆炸式的增长，这对数据存储与处理系统来了前所未有的挑战。传统的单一数据库难以承载此类大规模、强实时性的业务需求，因此，“全链路订单分析与库存管理系统”就是为了解决这些业务痛点而设计的，通过实时跟踪交易与库存状态，实现精细化的管理和决策支持，同时，借助GIS技术将复杂庞大的数据可视化展现在大屏电子地图上，使大量抽象、枯燥的数据变得更加直观和易于理解，也便于运营和决策者直观理解和快速响应。对订单数据进行智能高效的分析，为该电气公司研发和营销相关部门赋能，对物料研发和销售管理提供科学的数据支持。系统包括:实时物流监控模块、在线数据查询模块、数据GIS展示模块、大客户企业支持模块、智能统计分析模块、手机端等。")]),n._v(" "),v("p",[n._v("一、\n     鉴于该项目业务复杂、流程多，系统要涉及全国乃至全球分销商企业和直接客户企业的大量订单数据和物流数据分析处理、且工期短等特点，既要按期上线运行，又要实现基于分布式数据库的系统建设，我从数据库选型，数据库设计，应用数据集成和测试，以及分布式数据库部署等方面开展如下工作。数据库选型、现在的主流数据库都可以按分布式进行部署，例如SQLServer、Oracle、DB2、MySQQL等。\n公司有大量的基于MySQL数据库平台的分布式应用系统开发经验,经过大量的实践检验，其多用户并发处理、性能、数据自动备份等方面都表现良好,并且MySQL有丰富的社区支持。所以经过我们与建设方的沟通和内部讨论，我们决定在该项目中采用MySQL数据库来实现。而面对海量数据的分布式存储与处理需求，我们引入了Mycat2分布式数据库中间件，它具备优秀的数据分片、负载均衡、读写分离等功能，能够有效拓展MySQL的能力边界，实现跨地域、跨服务器的大规模分布式数据库部署。")]),n._v(" "),v("p",[n._v("二、\n     在XX电气有限公司的分布式数据库设计中，我们遵循了地域分布原则，以满足业务数据量庞大、安全性要求高的需求。首先，我们将全国范围内的分公司划分为多个数据分区，每个分区都设立了本地的MySQL数据库，以便存储和处理本地业务数据。这种做法的好处是能够降低数据传输的延迟，提高了本地业务数据的处理效率，同时也降低了对总部数据库系统的压力。与此同时，为了实现数据的集中管理和全局视野，我们在总部数据中心部署了全局MySQL数据库集群。这个集群负责汇聚、整合各地数据，通过Mycat2的分布式路由策略，实现数据在各节点间的透明分布与同步。通过Mycat2的帮助，我们能够轻松实现数据的透明分片、路由和同步，并且保证数据的实时性、一致性以及整体系统的高效性。我们在各个分公司设立的MySQL数据库中部署了Mycat2中间件，它实现了数据的分片存储，并根据分布式路由策略将数据传输至全局数据库集群。这样设计不仅提高了业务数据的读写效率，同时也保证了数据的安全性和稳定性。此外，为了确保数据的安全传输，我们在各分公司和总部数据中心之间建立了基于PPTP协议的VPN网络环境，同时结合防火墙技术，保障了数据传输的安全性和稳定性。")]),n._v(" "),v("p",[n._v("三、\n     在数据集成与测试过程中，我们深入运用了Mycat2的分片规则和分布式事务处理机制，特别是通过两阶段提交协议（2PC）保证了跨数据库事务的一致性。由于系统有些线上审批业务需要用到其他系统的数据，所以针对异构系统间的数据交换，我们自主研发了一款数据同步工具，可根据设定的时间间隔或事件触发，对全局数据库与各分公司数据库进行一致性校验和同步更新。在严格的系统测试阶段，我们挑选出业务代表性强、数据流量大的区域进行先行试点，对该区域内的订单处理、库存变动、物流数据同步等全流程进行了详尽的测试验证，确保系统在实际运行中的正确性和性能。测试通过调试没有问题后，在总公司和所有分公司进行了系统的上线部署和完整测试。\n在分布式数据库部署的具体实践中，我们充分利用MySQL Replication实现主从复制及读写分离，以此提升系统的读取性能并降低单点故障风险。全局数据库集群采用MySQL Cluster以确保高可用性和容错性，通过Mycat2智能路由策略，将读请求分散至多个从库，显著提升了查询性能。同时，借助MySQL Group Replication技术实现跨地域的数据同步，即便在网络不稳定或者部分节点失效情况下，也能确保数据的完整性和一致性。在系统安全层面，除了利用MySQL内置的安全机制外，我们还在分布式数据库通信中引入了SSL/TLS加密技术，确保数据在网络传输过程中的安全性。考虑到各地分公司网络环境的差异性，我们采用了OpenVPN技术构建分布式VPN网络环境，通过防火墙策略和NAT映射技术，确保了各地数据库节点间的稳定、安全连接。此外，针对可能出现的热点数据问题，我们通过Mycat2的动态数据分片策略，结合业务特点对热点数据进行特殊处理，如热点数据单独分片、使用Redis缓存优化等，有效地降低了数据库的压力，提升了系统整体性能。")]),n._v(" "),v("p",[v("strong",[n._v("总结")]),n._v("\n     历时一年，该项目于2023年3月顺利完成，并在随后的一年多时间里经受住了考验，系统运行稳定，各项功能均达到了甚至超越了预期目标，得到了用户的广泛认可。尽管在项目推进过程中曾遭遇过跨系统数据同步兼容性问题、热点数据处理挑战等困难，但通过团队紧密合作与技术创新，我们逐一攻克难关，不仅提升了系统的健壮性，也积累了宝贵的MySQL与Mycat2结合的分布式数据库架构设计与实施经验。未来，这套成功的架构方案将在更多大型分布式系统建设中发挥重要作用，我也通过这个项目学习到了不少经验。今后我将继续加强学习，总结经验教训，提高自己的能力。")]),n._v(" "),v("h2",{attrs:{id:"论微服务架构及其应用-完善"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#论微服务架构及其应用-完善"}},[n._v("#")]),n._v(" 论微服务架构及其应用（完善）")]),n._v(" "),v("p",[v("strong",[n._v("题目：论微服务架构及其应用\n近年来，随着互联网行业的迅猛发展，公司或组织业务的不断扩张，需求的快速变化以及用户量的不断增加，传统的单块(Monolithic)软件架构面临着越来越多的挑战，已逐渐无法适应互联网时代对软件的要求。在这一背景下，微服务架构模式(Microservice Architecture Pattern)逐渐流行，它强调将单一业务功能开发成微服务的形式，每个微服务运行在一个进程中;采用HTTP等通用协议和轻量级API实现微服务之间的协作与通信。这些微服务可以使用不同的开发语言以及不同数据存储技术，能够通过自动化部署工具独立发布，并保持最低限制的集中式管理，请围绕“论微服务架构及其应用”论题，依次从以下三个方面进行论述。\n1.概要叙述你参与管理和开发的、采用微服务架构的软件开发项目及在其中所担任的主要工作。\n2.与单块架构相比较，微服务架构有哪些特点?请列举至少4个特点并进行说明。\n3.结合你参与管理和开发的软件开发项目，描述该软件的架构说明该架构是如何采用微服务架构模式的，并说明在采用微服务架构后，在软件开发过程中遇到的实际问题和解决方案。")])]),n._v(" "),v("p",[v("strong",[n._v("范文：")])]),n._v(" "),v("p",[n._v('      2022年6月，我所在公司成功承接xx电气有限公司的 "智融链商平台"系统的建设项目。我作为项目的系统架构师和技术负责人，主要完成了需求的获取、分析，系统的架构设计等工作。该项目是基于互联网，为xx电气有限公司的工作人员和该公司的全体分销商相关业务人员提供下单、流程审批、物料管理、权限管理、基于客户大数据和订单大数据，进行智能分析，生成精准客户画像以及订单偏好等商业智能（Business Intelligence，BI）报表的服务平台。本文以此项目为基础，介绍了微服务架构在项目开发过程的应用，首先简要描述微服务架构的特点，然后具体阐述该平台微服务架构设计层次:应用层、业务服务层、基础服务层、微服务中间层和各微服务的划分设计:把系统按业务独立性和处理共性，划分为权限服务、流程服务、物料服务、客户服务、BI服务、订单服务等6个服务中心。最后说明微服务架构开发过程中遇到的实际问题和解决方法。经过9个月的努力，平台顺利开发完成并上线，通过近一年的用户反馈，整个系统运行稳定，达到了预期的目标和要求。 (摘要)')]),n._v(" "),v("p",[n._v("      对于xx电气有限公司的销售员和各级部门领导来说，繁杂的物料规则、客户和分销商的各级经销关系、复杂的线下特价和退货等业务审批流程已经严重影响了该公司的工作效率和成单率，且该公司老版本的CRM系统无法支持线上审批和利用大数据分析客户和订单数据，xx电气有限公司的IT部门负责人希望能建设一个全新的智能CRM管理平台，支持管理复杂的客户分销商关系、线上复杂流程审批、物料个性化配置以及管理和追踪订单的整个业务流程，同时能够通过对客户和订单的大数据分析赋能营销部，提高客户转化率和成单率。“智融链商平台”就是为了满足以上需求而开发的，系统包括：智能BI分析转化模块、工作流模块、客户智能化管理、物料配置管理、订单管理、售后管理、系统设置等七个模块。（项目背景）")]),n._v(" "),v("p",[n._v("      微服务架构是区分于传统架构方法(如SOA等)的一种全新架构设计思想。它的基本思想在于考虑围绕着业务领域组件来创建应用(服务)，这些应用(服务)可独立地进行开发、管理和部署每个微服务运行在一个进程中，采用HTTP等通信协议和轻量级API实现微服务之间的协作与通信。在分散的组件中使用微服务云架构和平台，使部署、管理和服务功能交付变得更加简单。相对于单体架构和SOA，它的主要特点是组件化、松耦合、自治、去中心化，体现在以下几个方面:\n1、一组小的服务。服务粒度小，每个服务是针对一个单一职责的业务能力的封装，专注做好一件事情。\n2、独立部署运行和扩展。每个服务能够独立被部署并运行在一个进程内。这种运行和部署方式能够赋予系统灵活的代码组织方式和发布节奏，使得快速交付和应对变化成为可能。\n3、独立开发和演化。技术选型灵活，不受遗留系统技术约束合适的业务问题选择合适的技术可以独立演化。服务与服务之间采取与语言无关的API进行集成。相对单体架构，微服务架构是更面向业务创新的一种架构模式。\n4、独立团队和自治。团队对服务的整个生命周期负责，工作在独立的上下文中，自己决策自己治理，而不需要统一的指挥中心。团队和团队之间通过松散的社区部落进行衔接。（技术介绍）")]),n._v(" "),v("p",[n._v("      在进行微服务架构设计时，我们将系统划分为应用层、业务服务层、基础服务层、微服务中间层。其中，业务服务层和基础服务层是业务价值体现的关键。\n1.应用层“以用户为中心”，专注于用户体验;\n2.业务服务层通过将系统专业化分工，采用服务化方式，提供“去中心化”服务调用，并通过服务编排组合，可快速满足多应用多前端(如电脑、平板、手机端)的功能实现。\n3.基础服务层。该层是服务重用和系统快速搭建的基础。微服务划分本质上是对业务功能进行解耦并独立部署，而具有共性的业务特性的功能进一步内聚和抽取，\n形成基础服务中心，在系统内或系统间的多个微服务中共享使用。基础服务中心包括认证授权中心、日志中心等公共服务应用。\n4.微服务中间件层。微服务中间件层主要实现服务的统一管理，为服务间的相互协作运行提供技术保障，是架构实现的技术支撑，主要包括:a.服务注册中心。通过集中的注册管理机制，统一管理服务名称与服务调用地址之间的映射关系，用于帮助服务之间互相感知彼此的存在。服务启动时会将自身的服务信息注册到注册中心，并订阅自己需要消费的服务，帮助服务调用者获取服务提供者的地址信息。\nb.服务网关。实现请求转发、动态路由等功能，可以降低服务演进过程中地址变动和增长带来的更新成本;也可以在网关中实现统一的过滤器进行数据过滤或者用户鉴权等功能。"),v("br"),n._v("\nc.服务负载均衡。通过水平伸缩实现服务调用请求的负载均衡有效分散单节点的计算负载，实现服务的弹性扩展。"),v("br"),n._v("\nd.服务容错。构建流量控制、故障隔离、断路器容错与修复机制避免某个服务的不可用，导致故障蔓延，并最终造成整个系统瘫痪的风险。"),v("br"),n._v("\ne.分布式缓存。利用键值数据库基于多台PC服务器，为分布式环境下应用对象缓存、状态缓存等场景提供统一的分布式缓存解决方案。")]),n._v(" "),v("p",[n._v("      服务划分。在微服务架构的需求分析和架构设计过程中，通常是用领域的动词和名词来划分微服务的，这种服务负责处理指定的实体或资源的所有操作。系统按业务独立性和处理共性，共划分为权限服务、流程服务、物料服务、客户服务、BI服务、订单服务等6个服务中心\n      应用开发实现。在系统开发阶段，一是基于公司原有的构件库快速构建服务的注册中心，配置中心、网关、负载均衡、容错、分布式缓存、定时任务、文件在线预览等中间件，为系统开发提供了运行基础。二是抽取分布式调度服务作为基础服务，采用任务“统一调度管理、分布式执行”模式，提供各应用任务的统一管理和应用间任务协作服务并可为其他项目建设重用。三是基于IDEA,Maven等工具，定制需要全新开发的服务，包括客户服务、物料服务、数据交互服务等每个微服务都可以使用适合此服务的不同的标准和技术来开发和使用服务，比如，在微服务架构下BI服务可以使用订单库和客户库获取数据，而物料服务使用物料库，这种方式是非常方便的。通过微服务架构设计，提高了系统的灵活性和可扩展性，在业务需求逐步清晰的情况下，实现功能快速迭代，开发过程应用敏捷开发模式。")]),n._v(" "),v("p",[n._v("      在项目的开发过程中，我们也遇到了一些问题，比如在xx电气有限公司进行物料促销活动的时候，客户下单需要进行复杂的线上流程审批，审批期间的数据流转处理会涉及多个微服务之间的互相调用，由于事先没有考虑到促销活动带来的大流量和高并发量，出现了客户和订单服务卡顿，接口响应时间延长等问题。后来通过分布式微服务监控系统及时发现了客户和订单微服务出现高负载的情况，我们通过快速无感知的新增多个订单和客户微服务集群，解决了卡顿问题。待促销活动结束后这些新部署的集群还可以做到无感知下线以节约服务器资源。（正文）")]),n._v(" "),v("p",[n._v("      2023年3月，整个项目顺利完成，通过近一年的用户反馈，整个系统运行稳定，达到了预期的目标和要求，受到了用户的好评。该系统也为后期我们基于微服务架构开发和处理微服务架构相关问题积累了宝贵的经验。")]),n._v(" "),v("h2",{attrs:{id:"论软件需求管理-完善"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#论软件需求管理-完善"}},[n._v("#")]),n._v(" 论软件需求管理(完善)")]),n._v(" "),v("p",[v("strong",[n._v("题目： 论软件需求管理")]),n._v("\n软件需求管理是一个对系统需求变更了解和控制的过程。需求管理过程与需求开发过程相互关联，初始需求导出的同时就要形成需求管理规划，一旦启动了软件开发过程，需求管理活动就紧密相伴。需求管理过程中主要包含变更控制、版本控制、需求跟踪和需求状态跟踪等4项活动，其目标是为项目管理人员建立一个软件需求基线，并保持软件计划、产品和活动与软件需求的一致性。\n请围绕“软件需求管理”论题，依次从以下三个方面进行论述。\n"),v("strong",[n._v("1.概要叙述你参与管理和开发的软件项目以及你在其中所担任的主要工作。\n2.详细描述需求管理过程中各个活动中的主要工作。\n3.详细说明你所参与的软件开发项目中，是如何进行软件需求管理的，实施的具体效果如何。")])]),n._v(" "),v("p",[v("strong",[n._v("范文：")]),n._v("\n一、摘要")]),n._v(" "),v("p",[n._v('      2022年6月，我所在公司成功中标xx电气有限公司的 "智融链商平台"系统的建设项目。我作为项目的系统架构设计师，主要进行了需求分析与需求管理、系统规划设计等工作。该系统主要包括:智能报表模块，客户模块，物料模块，物流模块，订单模块，权限管理等六个主要功能模块。 在项目开发过程中，我们通过面谈、召开联合需求计划会议、现场流程观摩等方法来获取用户需求，形成需求规格书并建立需求基线。在需求基线的基础之上通过变更管理委员会和变更管理系统进行需求变更管理，防止需求蔓延。采用禅道，有效的进行需求文档版本管理。并且建立需求跟踪矩阵，采用双向需求跟踪方法，防止需求的遗漏。通过对需求的有效控制管理，项目进展顺利，并通过最终验收经过1年多的实际运行，取得了令人满意的效果。')]),n._v(" "),v("p",[n._v("二、正文")]),n._v(" "),v("p",[n._v("      对于xx电气有限公司的销售员和各级部门领导来说，繁杂的物料规则、客户和分销商的各级经销关系、复杂的线下特价和退货等业务审批流程已经严重影响了该公司的工作效率和成单率，且该公司老版本的CRM系统无法支持线上审批和利用大数据分析客户和订单数据，xx电气有限公司的IT部门负责人希望能建设一个全新的智能CRM管理平台，支持管理复杂的客户分销商关系、线上复杂流程审批、物料个性化配置以及管理和追踪订单的整个业务流程，同时能够通过对客户和订单的大数据分析赋能营销部，提高客户转化率和成单率。“智融链商平台”就是为了满足以上需求而开发的，系统包括：智能报表模块，客户模块，物料模块，物流模块，订单模块，权限管理等六个主要功能模块。")]),n._v(" "),v("p",[n._v("     需求获取的完整、有效是需求管理的重要前提。在需求获取阶段我们采用用户访谈、召开联合需求计划会(JRP)，现场跟踪业务流程等方法，充分发现各种方法的优点，比如对于重点干系人，我们采用一对一的面谈方式来获取他们的需求，对于基层的具体业务需求和业务流程，采用召开联合需求计划会议，重点把握联合需求会议的会议组织和实施原则，将潜在的需求充分发掘出来。对于复杂的不易理解的业务流程，进行现场业务流程跟踪。在获取相对完整的需求后，采用穷举、归纳、抽象等方法对需求进行了整理和分析。采用穷举的方法可以避免需求遗漏;采用归纳的方法可以使问题更加条理化。最终形成需求规格说明书并与用户进行需求确认。通过需求确认，进一步消除歧义和对问题理解的不一致，最终建立需求基线。以后的需求管理是在此基线的基础上进行的。")]),n._v(" "),v("p",[n._v("需求变更管理是项目按计划进行的重要保证。虽然我们在前期的需求获取上做了大量工作，但在实际的项目进展过程中，需求变更还是不可避免的，如果不加以控制，会对项目的进度、成本、质量产生严重影响，甚至导致项目全面失败。当然管理需求变更的目的不是避免变更，而是有效的控制变更，减少变更对开发工作的影响，保证项目的正常进行。所以从这个角度来说，我们和用户的目标和利益是一致的。在这个项目中，我们通过统一渠道(变更管理委员会)、统一平台(变更管理系统)来进行需求变更管理。我们成立了变更管理委员会(CCB)，用户的所有变更申请必须以书面形式提交给CCB，CCB组织相关人员对此次变更进行评审，从变更对项目成本、进度、质量等因素产生的影响进行分析和评价，并根据需求变更的紧急程度给出审核结果:立即实施变更;有条件的实施变更;推迟到项目二期再进行实现。如果变更被批准，则提交给项目组开发人员进行变更实施，并通知相关干系人。在变更的实施过程中，需要对变更的执行情况进行跟踪，评价需求变更实施结果，作为组织过程资产进行记录，为以后的变更管理提供依据。在项目的进行过程中，由于需求的变化和频繁的发布可交付成果有大量的不同版本的文档、源代码等过程资产需要进行管理，版本控制软件为我们提供了完备的版本管理功能，用于存储、追踪目录(文件夹)和文件的修改历史，是项目开发的基础设施。它支持软件开发的配置管理活动，在这个项目中我们使用禅道。追踪多个版本的开发和维护活动，为我们进行需求文档的管理提供了极大的便利。")]),n._v(" "),v("p",[n._v("在很多项目中，需求跟踪都被有意无意的忽视了，但需求跟踪是需求管理的重要内容，必须引起我们的高度重视。需求跟踪是指\n跟踪一个需求使用期限的全过程，需求跟踪包括编制每个需求同系统元素之间的联系文档，这些元素包括其他类型的需求，体系\n结构，其他设计部件，源代码模块，测试，帮助文件等。是建立与维护“需求-设计-编程-测试”之间的一致性，确保所有的工作成\n果符合用户需求。在这个项目中，我们建立需求跟踪矩阵，并采用双向需求跟踪，所谓双向跟踪是指:正向跟踪和逆向跟踪。正向\n跟踪指检查《产品需求规格说明书》中的每个需求是否都能在后继工作成果中找到对应点。逆向跟踪指检查设计文档、代码、测\n试用例等工作成果是否都能在《产品需求规格说明书》中找到出处。通过需求跟踪矩阵和双向需求跟踪，防止了需求遗漏。")]),n._v(" "),v("p",[n._v("      2023年3月，整个项目顺利完成，通过近一年的用户反馈，整个系统运行稳定，达到了预期的目标和要求，不过也存在些不足，比如在进行退货流程设计时对于审批人员的设计不够灵活，导致流程中人员变更需要手动修改流程定义文件，后来我们针对该流程、进行优化设计成能够灵活一键变更流程处理人，解决了这个问题。该系统也为后期我们解决需求管理相关问题积累了宝贵的经验。经过这1年多的实际运行和用户反馈，整个系统运行稳定取得了用户的好评。")]),n._v(" "),v("h2",{attrs:{id:"论软件架构风格-完善"}},[v("a",{staticClass:"header-anchor",attrs:{href:"#论软件架构风格-完善"}},[n._v("#")]),n._v(" 论软件架构风格（完善）")]),n._v(" "),v("p",[v("strong",[n._v("题目： 论软件架构风格")]),n._v('\n软件体系结构风格是描述某一特定应用领域中系统组织方式的惯用模式。体系结构风格定义一个系统家族，即一个体系结构定义一个词汇表和一组约束。词汇表中包含一些构件和连接件类型而这组约束指出系统是如何将这些构件和连接件组合起来的。体系结构风格反应了领域中众多系统所共有的结构和语义特性，并指导如何将各个模块和子系统有效地组织成一个完整的系统，请围绕"论软件架构风格"论题，依次从以下三个方面进行论述\n'),v("strong",[n._v("1.概要叙述你参与分析和设计的软件系统开发项目以及你所担任的主要工作。\n2.软件系统开发中常用的软件架构风格有哪些?详细阐述每种风格的具体含义。\n3.详细说明你所参与分析和设计的软件系统是采用什么软件架构风格的，并分析采用该架构风格设计的原因。")])]),n._v(" "),v("p",[v("strong",[n._v("范文")]),n._v('\n一、摘要\n      2022年6月，我所在公司成功中标xx电气有限公司的 "智融链商平台"系统的建设项目。我作为项目的系统架构师和技术负责人，主要完成了需求的获取、分析，系统的架构设计等工作。该项目是基于互联网，为xx电气有限公司的工作人员和该公司的全体分销商相关业务人员提供下单、流程审批、物料管理、权限管理、基于客户大数据和订单大数据，进行智能分析，生成精准客户画像以及订单偏好等商业智能（Business Intelligence，BI）报表的服务平台。由于公司开展的就是智能客户关系管理类软件的研发，有一定的技术积累和构件库，所以我们结合该项目的特点采用J2EE轻量级架构使用SSM框架作为系统的基础平台，充分体现了Spring的高开发效率，易测试性及可移植性等优点。系统分为表现层、业务逻辑层和数据访问层，还包括一个xx电气有限公司的企业应用集成层。在表现层，企业通过TCP/IP方式和业务层交互信息，使用SpringMVC完成表现层的数据展示。业务逻辑层负责处理系统中的各类业务逻辑，采用SpringMVC+Spring+Mybatis。企业应用集成层，涉及数据较多，除从本系统获取数据外，还需要从其它系统，如:WMS仓管系统、APS交期预测系统等获取数据以支持本系统的在线审批需要。通过近一年的用户反馈，整个系统运行稳定，达到了预期的目标和要求。')]),n._v(" "),v("p",[n._v("二、正文\n      对于xx电气有限公司的销售员和各级部门领导来说，繁杂的物料规则、客户和分销商的各级经销关系、复杂的线下特价和退货等业务审批流程已经严重影响了该公司的工作效率和成单率，且该公司老版本的CRM系统无法支持线上审批和利用大数据分析客户和订单数据，xx电气有限公司的IT部门负责人希望能建设一个全新的智能CRM管理平台，支持管理复杂的客户分销商关系、线上复杂流程审批、物料个性化配置以及管理和追踪订单的整个业务流程，同时能够通过对客户和订单的大数据分析赋能营销部，提高客户转化率和成单率。“智融链商平台”就是为了满足以上需求而开发的，系统包括：智能BI分析转化模块、工作流模块、客户智能化管理、物料配置管理、订单管理、售后管理、系统设置等七个模块。")]),n._v(" "),v("p",[n._v("      系统架构风格反应了领域中众多系统所共有的结构和语义特性它可以指导我们如何将系统的各个模块和子系统有效地组织成一个完整的系统。常用的架构风格包括:层次式架构风格，3层/多层架构风格，基于层次消息总线的架构风格等。\n1.层次式架构风格将系统组织成一个层次结构，每一层为上层提供服务，并接受下层客户提供的服务。各层之间只对相邻的层可见，所以每一层最多只影响两层，同时只要给相邻层提供相同的接口，允许每层用不同的方法实现，为软件重用提供了强大的支持。层次系统最广泛的应用是分层通信协议，如:OSI和TCP/IP。\n2.3层/多层架构风格:三层/多层架构就是将应用功能分成表示层、业务逻辑层和数据层三部分(或更多)，每一层分别放在不同的硬件平台上，实现单一的功能。可维护性好，灵活性高，更加安全，能够适应负载增加。\n3.基于层次消息总线的架构风格:此风格支持构件的分布和并发，构件之间通过消息总线进行通讯，消息总线是系统的连接件，负责消息的分派、传递和过滤以及处理结果的返回。各个构件挂接在消息总线上，向总线登记感兴趣的消息类型构件根据需要发出消息，由消息总线负责把该消息分派到系统中所有对此消息感兴趣的构件，消息是构件之间通讯的唯一方式构件接收到消息后，根据自身状态对消息进行响应，并通过总线返回处理结果。\n由于我们公司长年开展的就是CRM类行业软件的研发，有大量的技术积累和构件库，所以我们针对该系统采用了多层架构风格，\n在已有的领域模型基础之上，重用基础设施，完成系统的架构设计，强调极短的开发周期，通过大量使用可复用构件，\n采用基于构件的建造方法赢得快速开发。")]),n._v(" "),v("p",[n._v("一、架构设计\n      在进行了充分的需求分析的基本上，我们采用了J2EE轻量级架构使用Spring框架作为系统的基础平台，分为表现层、业务逻辑层和数据访问层，还包括一个xx电气有限公司的企业应用集成层。在表现层，企业通过TCP/IP方式和应用层交互信息，在表现层使用SpringMVC的返回体返回数据给前端用于生成页面显示效果，供用户使用。企业应用集成层，涉及数据较多，除从本系统获取数据外，还需要从其它系统，\n如:在WMS仓管系统、APS交期预测系统等获取数据以支持本系统的在线审批需要。\n业务逻辑层是系统的核心，负责处理系统中的各类业务逻辑，采用Spring+SpringMVC+Mybatis，为了分离控制层与业务逻辑层又可细分为:\n(1)Web层，就是MVC模式里的“c”(Controller)，负责表示层与业务逻辑层的交互，调用业务逻辑层，并将业务数据返回给表示层显示。\n(2)service层(业务逻辑层)，负责实现业务逻辑，对DAO对象进行正面模式的封装。\n(3)DAO层(数据访问对象层)，负责与持久化对象交互，封装了数据的增、删、改、查等数据访问操作。\n(4)PO层(持久化对象层)，通过实体/关系映射工具将关系数据库中的数据映射成对象，实现以面向对象方式操作关系数据库，通过使用SpringMVC，提供了良好的MVC模式，所有的用户请求都由SpringMVC的DispatcherServlet负责接受处理，然后通过Spring提供自动装配功能，定位Spring容器中的业务逻辑组件，调用业务逻辑组件方法处理用户请求。数据服务层使用MySQL关系数据库存储数据。架构设计完成后，我们还邀请领域专家和客户IT部门同事一起，组织讨论会议的形式对架构设计进行了评审，看该架构是否可以满足系统功能要求和质量要求。通过专家以及客户的讨论，一致认为架构设计是可以达到系统要求的。")]),n._v(" "),v("p",[n._v("二、架构实现\n      实现原理以Spring为核心，承上启下。向上管理表示层，向下管理业务逻辑层组件，同时负责管理业务逻辑层所需的DAO对象，负责在各层之间传值的是值对象\n1.实现Web层:系统使用SpingMVC作为前端MVC框架，SprigMVC 的DispatcherServlet组件负责接收用户请求，并通过HandlerMapping\n找到适合处理该请求的处理器（Controller），由处理器执行业务逻辑，并返回一个 ModelAndView 对象，该对象包含了模型数据和视图信息，最后通过ViewResolver组件解析视图将数据或者真正的视图返回给前端页面。在SpingMVC中使用Interceptor组件过滤拦截符合规则的用户请求，并将用户请求直接转入到SpingMVC框架内。通过这种方式，可以灵活配置对用户请求的过滤操作，保证了用户无法直接浏览任何需要安全验证的页面，提高系统安全性。")]),n._v(" "),v("p",[n._v("2.实现业务逻辑层:业务逻辑层采用面向接口编程原则，为了让系统中的控制器不依赖于业务逻辑组件的实现类，而依赖于业务逻辑组件的接口，达到降低系统重构的代价。该系统中使用Spring的邮件抽象层，比如当企业办理的业务审核通过后，系统向企业用户发送邮件进行通知。还使用基于spring的任务调度机制更新订单的物流状态，该任务每隔一段时间会自动执行，不用以硬编码的方式编写在程序中，而是通过spring的配置文件完成。由于SpringAOP提供声明式事务管理功能，所以在业务逻辑组件方法内无须编写事务管理代码，将事务管理写在配置文件中，由Spring容器管理事务。\n3.实现持久化层:为实现Mybatis持久层，需定义实体类以及配置对应的映射文件。根据该系统实现的功能需要定义的实体类为:用户、物料、订单、审批等，这些实体类分别对应各自的数据表，Mybatis可通过各自的Mapper类来访问数据表。为了进行数据持久化访问，必须配置实体类对应的表，其中每个持久化类对应数据库中的一张表，持久化类中的每个属性对应数据表中的字段，持久化类的每个实例对应数据表中\n每一行记录。")]),n._v(" "),v("p",[n._v("三、总结\n2023年3月，整个项目顺利完成，通过近一年的用户反馈，整个系统运行稳定，达到了预期的目标和要求，受到了用户的好评，\n但也存在些不足，比如在更新物流状态的时候，由于系统部署多个实例导致重复更新物流状态浪费系统资源，后来通过使用Redis实现分布式锁解决了重复更新问题。通过该系统的架构设计也为后期我们基于分层架构风格设计开发和处理分层架构相关问题积累了宝贵的经验。")])])}),[],!1,null,null,null);v.default=s.exports}}]);